    let trendChart = '';
    if (overall.recentTrend.length > 0) {
      const max = Math.max(...overall.recentTrend, 1);
      trendChart = '<div style="display:flex;align-items:flex-end;height:50px;gap:3px;margin:8px auto;justify-content:center">';
